  ('fire-eq-tech-moex-02896', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「消防法施行細則」、「爆竹煙火管理條例施行細則」、「公共危險物品及可燃性高壓氣體設置標準 暨安全管理辦法」、「申請暫行從事消防安全設備設計監造裝置及檢修人員須知」等規定，有關講習訓練 的時數，下列敘述何者有誤？', '["防火管理人16小時", "爆竹煙火監督人16小時", "保安監督人24小時", "申請暫行從事消防安全設備設計監造人員32小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
